const AWS = require('aws-sdk');
const dynamoDb = new AWS.DynamoDB.DocumentClient();
const sqs = new AWS.SQS();

exports.handler = async (event) => {
    const queueUrl = 'YOUR_SQS_QUEUE_URL';
    const batchSize = 10; // Adjust based on your needs

    try {
        let moreMessages = true;
        let processedCount = 0;

        while (moreMessages && processedCount < event.Records.length) {
            const batchRecords = event.Records.slice(processedCount, processedCount + batchSize);
            const orderIds = batchRecords.map(record => JSON.parse(record.body).orderId);

            // Process orders and call payment APIs
            for (const orderId of orderIds) {
                try {
                    await processOrder(orderId);
                } catch (error) {
                    console.error(`Error processing order ${orderId}:`, error);
                }
            }

            processedCount += batchSize;
        }

    } catch (error) {
        console.error('Error processing batch:', error);
    }
};

async function processOrder(orderId) {
    // Simulate payment API call
    await simulatePaymentAPI(orderId);

    // Update DynamoDB
    const params = {
        TableName: 'OrdersTable',
        Key: { orderId },
        ExpressionAttributeValues: { ':s': 'Processed' },
        UpdateExpression: 'set status = :s'
    };

    try {
        await dynamoDb.update(params).promise();
    } catch (error) {
        console.error('Error updating DynamoDB:', error);
    }
}

